import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Layout } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminSectionForm = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ Section_ID: '', Title_En: '', Title_Ar: '', Description_En: '' });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await AdminService.upsertSection(formData);
      toast.success("Section Matrix Defined");
      navigate('/admin/sections');
    } catch (err) { toast.error("System Fault"); }
  };

  const inputStyle = "w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 font-bold outline-none border border-transparent focus:border-primary transition-all text-xs";

  return (
    <div className="max-w-2xl mx-auto space-y-8 p-12">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-[10px] font-black uppercase text-gray-400">
        <ArrowLeft size={14} /> Back to Hierarchy
      </button>
      <div className="bg-white dark:bg-[#0a0a0a] p-12 rounded-[3rem] border shadow-sm">
        <h2 className="text-3xl font-black uppercase italic mb-8 flex items-center gap-4">
          <Layout className="text-primary" /> Define <span className="text-primary">Section</span>
        </h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <input placeholder="Section ID (e.g. SEC01)" className={inputStyle} onChange={e => setFormData({...formData, Section_ID: e.target.value})} />
          <input placeholder="Title (Eng)" className={inputStyle} onChange={e => setFormData({...formData, Title_En: e.target.value})} />
          <textarea placeholder="Description" rows={4} className={inputStyle} onChange={e => setFormData({...formData, Description_En: e.target.value})} />
          <button className="w-full py-5 bg-black text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-primary transition-all shadow-xl">Stabilize Section</button>
        </form>
      </div>
    </div>
  );
};
